sql:
SELECT gene_id
FROM gene_set_genes
WHERE gene_set_id = 0;

SELECT COUNT(gene_id) as gene_count
FROM gene_set_genes
WHERE gene_set_id = 0;

SELECT gene_set_name, last_modified_date
FROM gene_sets
ORDER BY last_modified_date DESC;

SELECT DISTINCT pe.pathway_id
FROM pathway_enrichment pe
WHERE pe.term IN ('MT1E', 'MT1F', 'MT1G', 'MT1X', 'MT2A');

SELECT gene_id
FROM regulation
WHERE regulation_type = 'up-regulated';

SELECT AVG(gene_count) AS avg_genes_per_pathway
FROM (
    SELECT pathway_id, COUNT(gene_id) AS gene_count
    FROM gene_pathway_associations
    GROUP BY pathway_id
);
